const msg = $input.item.json.message || {};
const texto = (msg.text || '').trim();
const chatId = msg.chat ? String(msg.chat.id) : '';
const fromId = msg.from ? String(msg.from.id) : '';
const DIRETOR_ID = '8895733647'; // LEDGER: Telegram chat_id do Diretor -- identidade fixa, nao valor de negocio

const isDiretor = (chatId === DIRETOR_ID || fromId === DIRETOR_ID);

if (!isDiretor) {
  return [{ json: { valido: false, motivo: 'Acesso nao autorizado. Apenas o Diretor emite vereditos.', chatId: chatId || fromId } }];
}

const cmdMatch = texto.match(/^\/(aprovar|rejeitar|veredito)\s+(.+)/i);
if (!cmdMatch) {
  return [{ json: { valido: false, motivo: 'Formato invalido. Use: /aprovar A  ou  /rejeitar B  ou  /veredito D1:A D2:B', chatId: chatId } }];
}

const cmd = cmdMatch[1].toLowerCase();
const arg = cmdMatch[2].trim().toUpperCase();

let itens = [];
if (cmd === 'veredito') {
  const matches = arg.match(/D\d+:[ABC]/gi);
  if (matches) itens = matches.map(function(m){ return { id: m.split(':')[0], veredito: m.split(':')[1] }; });
} else {
  const v = cmd === 'aprovar' ? 'A' : 'B';
  itens = [{ id: arg, veredito: v }];
}

if (!itens.length) {
  return [{ json: { valido: false, motivo: 'Nenhum item reconhecido. Use D1:A D2:B', chatId: chatId } }];
}

const agora = new Date();
const tsFile = agora.toISOString().replace(/[^0-9]/g, '').slice(0, 12);
const dataHora = agora.toISOString().replace('T',' ').slice(0,16) + ' UTC';

return [{ json: { valido: true, isDiretor: true, cmd: cmd, itens: itens, chatId: chatId, tsFile: tsFile, dataHora: dataHora } }];

const item = $('Parsear Comando').item.json;

const nomeArquivo = 'VEREDITOS/VEREDITOS_' + item.tsFile + '.json';

const payload = {
  timestamp: new Date().toISOString(),
  dataHora: item.dataHora,
  vereditos: item.itens,
  fonte: 'telegram',
  diretor_confirmado: true
};
const payloadB64 = Buffer.from(JSON.stringify(payload, null, 2), 'utf8').toString('base64');
const commitMsg = 'veredito(telegram): ' + item.itens.map(function(i){ return i.id + ':' + i.veredito; }).join(', ');

const blocos = [];
blocos.push({
  object: 'block',
  type: 'heading_3',
  heading_3: { rich_text: [{ type: 'text', text: { content: 'Vereditos ' + item.dataHora } }] }
});
item.itens.forEach(function(i) {
  const label = i.veredito === 'A' ? 'APROVADO' : (i.veredito === 'B' ? 'DEVOLVER' : i.veredito);
  blocos.push({
    object: 'block',
    type: 'bulleted_list_item',
    bulleted_list_item: { rich_text: [{ type: 'text', text: { content: i.id + ' - ' + label } } ] }
  });
});
blocos.push({
  object: 'block',
  type: 'paragraph',
  paragraph: { rich_text: [{ type: 'text', text: { content: 'Arquivo: ' + nomeArquivo }, annotations: { italic: true, color: 'gray' } }] }
});

const linhasConfirm = item.itens.map(function(i){
  const label = i.veredito === 'A' ? 'APROVADO' : (i.veredito === 'B' ? 'DEVOLVER' : i.veredito);
  return '  - ' + i.id + ': ' + label;
}).join('\n');

const confirmacao = 'Veredito registrado!\n' + linhasConfirm + '\n\nArquivo: ' + nomeArquivo + '\n' + item.dataHora;

return [{ json: {
  notionChildren: blocos,
  confirmacao: confirmacao,
  chatId: item.chatId,
  nomeArquivo: nomeArquivo,
  payloadB64: payloadB64,
  commitMsg: commitMsg
} }];
